/**
 * UT Oracle — External Integration SDK
 * Universal Transmissions
 *
 * Connects external apps to UT Oracle (guest, free, initiate plans).
 * Auth: Supabase Auth (email + password)
 * Plan: Supabase profiles table via UT billing API
 */

(function (root, factory) {
  if (typeof module === 'object' && typeof module.exports === 'object') {
    module.exports = factory()
  } else {
    root.UTOracleClass = factory()
    root.__utOracleInstance = root.__utOracleInstance || new root.UTOracleClass()
    root.UTOracle = root.__utOracleInstance
    root.getUTOracle = function () { return Promise.resolve(root.__utOracleInstance) }
  }
}(typeof self !== 'undefined' ? self : this, function () {
  'use strict'

  // ─── Config ───────────────────────────────────────────────────────────────
  var UT_SUPABASE_URL = 'https://opixpkquyapeqdceyczs.supabase.co'
  var UT_SUPABASE_ANON = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9waXhwa3F1eWFwZXFkY2V5Y3pzIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ3ODM2NzgsImV4cCI6MjA5MDM1OTY3OH0.clqq-XAE7NgY7muFnNqQfhJcLv2i_CALK0d6Kg4P_eQ'
  var UT_BASE_URL = 'https://www.universal-transmissions.com'
  var ORACLE_API = UT_BASE_URL + '/api/oracle'
  var BILLING_API = UT_BASE_URL + '/api/billing'

  // ─── Storage helpers ─────────────────────────────────────────────────────
  function storageGet(key) {
    try { return localStorage.getItem(key) } catch (e) { return null }
  }
  function storageSet(key, val) {
    try { localStorage.setItem(key, val) } catch (e) {}
  }
  function storageRemove(key) {
    try { localStorage.removeItem(key) } catch (e) {}
  }

  // ─── Anonymous ID ────────────────────────────────────────────────────────
  function getAnonymousId() {
    var key = 'ut_anonymous_id'
    var id = storageGet(key)
    if (!id) {
      id = (typeof crypto !== 'undefined' && crypto.randomUUID)
        ? crypto.randomUUID()
        : 'anon-' + Date.now() + '-' + Math.random().toString(16).slice(2)
      storageSet(key, id)
    }
    return id
  }

  // ─── UT Oracle Class ─────────────────────────────────────────────────────
  function UTOracle() {
    this._accessToken = null
    this._refreshToken = null
    this._user = null
    this._supabase = null
    this._supabasePromise = null
    this._loadTokens()
    this._loadSupabase()
  }

  UTOracle.prototype._loadSupabase = function () {
    var self = this
    if (this._supabasePromise) return
    this._supabasePromise = new Promise(function (resolve) {
      if (window.Supabase) {
        self._supabase = window.Supabase
        resolve(window.Supabase)
        return
      }
      var script = document.createElement('script')
      script.src = 'https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2'
      script.onload = function () {
        self._supabase = window.Supabase
        resolve(window.Supabase)
      }
      document.head.appendChild(script)
    })
  }

  UTOracle.prototype._getSupabase = function () {
    var self = this
    return this._supabasePromise.then(function (Sb) {
      if (!self._supabaseClient) {
        self._supabaseClient = new Sb.createClient(UT_SUPABASE_URL, UT_SUPABASE_ANON, {
          auth: {
            persistSession: true,
            autoRefreshToken: true,
            storage: {
              getItem: storageGet,
              setItem: storageSet,
              removeItem: storageRemove,
            }
          }
        })
      }
      return self._supabaseClient
    })
  }

  // ── Session sharing (UT site → prototypes) ──────────────────────────────
  UTOracle.prototype._setUTSession = function () {
    // Called by UT site: window.__utSetSession(email, plan)
    if (typeof window !== 'undefined' && window.__utSetSession) {
      try {
        window.__utSetSession(this._user ? this._user.email : null, this._user ? this._user.plan : null)
      } catch (e) {}
    }
  }

  // ── Auth ─────────────────────────────────────────────────────────────────
  UTOracle.prototype.signUp = function (email, password, fullName) {
    var self = this
    email = (email || '').trim().toLowerCase()
    return this._getSupabase().then(function (sb) {
      return sb.auth.signUp({
        email: email,
        password: password,
        options: { data: { full_name: fullName || '' } }
      })
    }).then(function (result) {
      if (result.error) throw new Error(result.error.message)
      if (!result.data.user || !result.data.session) {
        throw new Error('Confirmation email sent. Please check your inbox and click the link.')
      }
      self._accessToken = result.data.session.access_token
      self._refreshToken = result.data.session.refresh_token
      self._saveTokens()
      return self._resolvePlan(email).then(function (plan) {
        self._user = { id: result.data.user.id, email: result.data.user.email, plan: plan }
        self._setUTSession()
        return self._user
      })
    })
  }

  UTOracle.prototype.signIn = function (email, password) {
    var self = this
    email = (email || '').trim().toLowerCase()
    return this._getSupabase().then(function (sb) {
      return sb.auth.signInWithPassword({ email: email, password: password })
    }).then(function (result) {
      if (result.error) throw new Error(result.error.message)
      if (!result.data.user || !result.data.session) {
        throw new Error('Sign-in failed.')
      }
      self._accessToken = result.data.session.access_token
      self._refreshToken = result.data.session.refresh_token
      self._saveTokens()
      return self._resolvePlan(email).then(function (plan) {
        self._user = { id: result.data.user.id, email: result.data.user.email, plan: plan }
        self._setUTSession()
        return self._user
      })
    })
  }

  UTOracle.prototype.signOut = function () {
    var self = this
    return this._getSupabase().then(function (sb) {
      return sb.auth.signOut()
    }).then(function () {
      self._clearTokens()
      if (typeof window !== 'undefined' && window.__utClearSession) {
        window.__utClearSession()
      }
    })
  }

  Object.defineProperty(UTOracle.prototype, 'currentUser', {
    get: function () { return this._user }
  })

  Object.defineProperty(UTOracle.prototype, 'isLoggedIn', {
    get: function () { return !!(this._accessToken && this._user) }
  })

  // ── Persistence ──────────────────────────────────────────────────────────
  UTOracle.prototype._loadTokens = function () {
    try {
      var raw = storageGet('ut_oracle_session')
      if (raw) {
        var s = JSON.parse(raw)
        this._accessToken = s.accessToken || null
        this._refreshToken = s.refreshToken || null
      }
    } catch (e) {}
    // Restore user from UT session if available
    try {
      var raw2 = storageGet('ut_session')
      if (raw2) {
        var s2 = JSON.parse(raw2)
        if (s2 && s2.email) {
          this._user = { email: s2.email, plan: s2.plan || 'guest', id: '', accessToken: this._accessToken, refreshToken: this._refreshToken }
        }
      }
    } catch (e) {}
  }

  UTOracle.prototype._saveTokens = function () {
    storageSet('ut_oracle_session', JSON.stringify({
      accessToken: this._accessToken,
      refreshToken: this._refreshToken
    }))
  }

  UTOracle.prototype._clearTokens = function () {
    this._accessToken = null
    this._refreshToken = null
    this._user = null
    storageRemove('ut_oracle_session')
  }

  // ── Plan resolution ──────────────────────────────────────────────────────
  UTOracle.prototype._resolvePlan = function (email) {
    var self = this
    var headers = {}
    if (this._accessToken) headers['Authorization'] = 'Bearer ' + this._accessToken
    return fetch(UT_BASE_URL + '/api/integration/plan?email=' + encodeURIComponent(email), { headers: headers })
      .then(function (r) { return r.ok ? r.json() : {} })
      .then(function (data) {
        return (data && data.plan) ? data.plan : 'guest'
      })
      .catch(function () { return 'guest' })
  }

  // ── Usage ────────────────────────────────────────────────────────────────
  UTOracle.prototype.getUsage = function (anonymousId) {
    var params = ''
    if (!this.isLoggedIn && anonymousId) {
      params = '?anonymous_id=' + encodeURIComponent(anonymousId)
    }
    var headers = {}
    if (this._accessToken) headers['Authorization'] = 'Bearer ' + this._accessToken
    return fetch(ORACLE_API + '/usage' + params, { headers: headers })
      .then(function (r) { return r.ok ? r.json() : {} })
      .catch(function () { return {} })
  }

  // ── Oracle question ──────────────────────────────────────────────────────
  UTOracle.prototype.askOracle = function (question, options) {
    var self = this
    options = options || {}
    var body = { question: question }
    if (options.anonymousId) body.anonymous_id = options.anonymousId
    if (options.mode) body.mode = options.mode
    if (options.language) body.language = options.language

    var headers = { 'Content-Type': 'application/json' }
    if (this._accessToken) headers['Authorization'] = 'Bearer ' + this._accessToken

    return fetch(ORACLE_API + '/route', {
      method: 'POST',
      headers: headers,
      body: JSON.stringify(body)
    }).then(function (r) {
      if (!r.ok) {
        return r.json().then(function (e) { throw new Error(e.error || 'Oracle error') })
      }
      // Fire-and-forget usage increment
      self._incrementUsage(options.anonymousId).catch(function () {})
      return r.json()
    })
  }

  UTOracle.prototype._incrementUsage = function (anonymousId) {
    var body = {}
    if (anonymousId) body.anonymous_id = anonymousId
    var headers = { 'Content-Type': 'application/json' }
    if (this._accessToken) headers['Authorization'] = 'Bearer ' + this._accessToken
    return fetch(ORACLE_API + '/usage', {
      method: 'POST',
      headers: headers,
      body: JSON.stringify(body)
    })
  }

  // ── Plan & billing ───────────────────────────────────────────────────────
  UTOracle.prototype.getPlanStatus = function () {
    var self = this
    if (!this.isLoggedIn) return Promise.resolve({ plan: 'guest', stripeCustomerId: null })
    var headers = {}
    if (this._accessToken) headers['Authorization'] = 'Bearer ' + this._accessToken
    return fetch(UT_BASE_URL + '/api/integration/plan?email=' + encodeURIComponent(this._user.email), { headers: headers })
      .then(function (r) { return r.ok ? r.json() : { plan: 'guest' } })
      .catch(function () { return { plan: 'guest' } })
  }

  UTOracle.prototype.startInitiateCheckout = function (returnUrl) {
    if (!this.isLoggedIn) return Promise.reject(new Error('Must be logged in'))
    var headers = { 'Content-Type': 'application/json' }
    if (this._accessToken) headers['Authorization'] = 'Bearer ' + this._accessToken
    return fetch(BILLING_API + '/checkout', {
      method: 'POST',
      headers: headers,
      body: JSON.stringify({ returnUrl: returnUrl })
    }).then(function (r) {
      if (!r.ok) return r.json().then(function (e) { throw new Error(e.error || 'Checkout failed') })
      return r.json().then(function (d) { return d.url })
    })
  }

  UTOracle.prototype.subscribeToInitiate = function (returnUrl) {
    var url = returnUrl || (typeof window !== 'undefined' ? window.location.href + '?subscribed=1' : '')
    return this.startInitiateCheckout(url).then(function (checkoutUrl) {
      if (typeof window !== 'undefined') window.location.href = checkoutUrl
    })
  }

  UTOracle.prototype.refreshSession = function () {
    var self = this
    this._accessToken = null
    this._refreshToken = null
    this._user = null
    storageRemove('ut_oracle_session')
    return this._getSupabase().then(function (sb) {
      return sb.auth.refreshSession()
    }).then(function (result) {
      if (result.data && result.data.session) {
        self._accessToken = result.data.session.access_token
        self._refreshToken = result.data.session.refresh_token
        self._saveTokens()
        return self._resolvePlan(result.data.user.email).then(function (plan) {
          self._user = { id: result.data.user.id, email: result.data.user.email, plan: plan }
          self._setUTSession()
          return self._user
        })
      }
      return null
    }).catch(function () { return null })
  }

  // ─── Boot ────────────────────────────────────────────────────────────────
  // Auto-restore session from localStorage + UT shared session
  ;(function () {
    try {
      var raw = storageGet('ut_oracle_session')
      if (raw) {
        var s = JSON.parse(raw)
        if (s && s.accessToken) {
          UTOracle.prototype._accessToken = s.accessToken
          UTOracle.prototype._refreshToken = s.refreshToken || null
        }
      }
      var raw2 = storageGet('ut_session')
      if (raw2) {
        var s2 = JSON.parse(raw2)
        if (s2 && s2.email) {
          UTOracle.prototype._user = { email: s2.email, plan: s2.plan || 'guest', id: '', accessToken: UTOracle.prototype._accessToken, refreshToken: UTOracle.prototype._refreshToken }
        }
      }
    } catch (e) {}
  })()

  return UTOracle
}))